    const nodeMap = new Map<string, EntityGraphNodeView>()
    for (const match of matches) {
      nodeMap.set(match.id, toEntityGraphNode(match))
      for (const related of graph.findRelated(match.id, 1)) {
        if (!nodeMap.has(related.id)) {
